module shift_reg_4bit (CLK, RST, SI, Q);
input CLK, RST, SI;
output reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RST) begin
        Q <= 4'b0000;
    end else begin
        Q <= {SI, Q[3:1]};
    end
end

endmodule
